<template><div class="page-wrap"><section class="page-hero"><div><span class="eyebrow">MEDICINE INVENTORY</span><h1>药品管理</h1><p>维护药品目录、价格、生产信息与实时库存</p></div><div class="inventory-note"><el-icon><Box /></el-icon><div><span>库存预警</span><strong>{{lowStockCount}} 种药品库存偏低</strong></div></div></section><section class="content-card"><div class="card-toolbar"><div><h2>药品目录</h2><p>支持关键词搜索、分类筛选和库存调整</p></div><div class="toolbar-actions"><el-input v-model="keyword" :prefix-icon="Search" placeholder="搜索药品" clearable @keyup.enter="search"/><el-select v-model="categoryId" placeholder="全部分类" clearable @change="search"><el-option v-for="c in categories" :key="c.id" :label="c.name" :value="c.id"/></el-select><el-button class="soft-btn" :icon="Refresh" @click="loadData">刷新</el-button><el-button type="primary" class="primary-btn" :icon="Plus" @click="openAdd">新增药品</el-button></div></div><el-table :data="list" v-loading="loading" class="admin-table"><el-table-column label="药品" min-width="200"><template #default="{row}"><div class="medicine-cell"><span><el-icon><FirstAidKit /></el-icon></span><div><strong>{{row.name}}</strong><small>{{row.manufacturer||'生产厂家未填写'}}</small></div></div></template></el-table-column><el-table-column prop="categoryName" label="分类" width="120"><template #default="{row}"><el-tag effect="light" round>{{row.categoryName||'未分类'}}</el-tag></template></el-table-column><el-table-column prop="specification" label="规格" min-width="125"/><el-table-column label="价格" width="105"><template #default="{row}"><strong class="price">¥{{Number(row.price||0).toFixed(2)}}</strong></template></el-table-column><el-table-column label="库存" width="130"><template #default="{row}"><div class="stock"><strong :class="{low:row.stock<20}">{{row.stock}} {{row.unit}}</strong><span :class="row.stock<20?'warn':'ok'">{{row.stock<20?'库存偏低':'库存正常'}}</span></div></template></el-table-column><el-table-column label="操作" width="215" fixed="right"><template #default="{row}"><el-button link type="primary" @click="openEdit(row)">编辑</el-button><el-button link type="warning" @click="openStock(row)">调整库存</el-button><el-button link type="danger" @click="remove(row)">删除</el-button></template></el-table-column></el-table><div class="pagination-bar"><span>共 {{total}} 种药品</span><el-pagination v-model:current-page="page" :page-size="size" :total="total" layout="prev,pager,next" @current-change="loadData"/></div></section><el-dialog v-model="dialog" :title="form.id?'编辑药品':'新增药品'" width="680px" destroy-on-close><el-form ref="formRef" :model="form" :rules="rules" label-position="top" class="dialog-form"><div class="form-grid"><el-form-item label="药品名称" prop="name"><el-input v-model="form.name"/></el-form-item><el-form-item label="药品分类"><el-select v-model="form.categoryId" style="width:100%" @change="changeCategory"><el-option v-for="c in categories" :key="c.id" :label="c.name" :value="c.id"/></el-select></el-form-item><el-form-item label="规格"><el-input v-model="form.specification" placeholder="例如：0.5g*24粒"/></el-form-item><el-form-item label="单位"><el-select v-model="form.unit" style="width:100%"><el-option v-for="u in ['盒','瓶','袋','支']" :key="u" :label="u" :value="u"/></el-select></el-form-item><el-form-item label="单价（元）" prop="price"><el-input-number v-model="form.price" :min="0" :precision="2" style="width:100%"/></el-form-item><el-form-item label="初始库存" prop="stock"><el-input-number v-model="form.stock" :min="0" style="width:100%" :disabled="Boolean(form.id)"/></el-form-item><el-form-item label="生产厂家" class="span-two"><el-input v-model="form.manufacturer"/></el-form-item><el-form-item label="药品说明" class="span-two"><el-input v-model="form.description" type="textarea" :rows="3" maxlength="500" show-word-limit/></el-form-item></div></el-form><template #footer><el-button @click="dialog=false">取消</el-button><el-button type="primary" class="primary-btn" :loading="saving" @click="save">保存药品</el-button></template></el-dialog><el-dialog v-model="stockDialog" title="调整药品库存" width="440px"><div class="stock-dialog"><div><span>药品</span><strong>{{current?.name}}</strong></div><div><span>当前库存</span><strong>{{current?.stock}} {{current?.unit}}</strong></div><el-alert title="输入正数增加库存，输入负数减少库存" type="info" :closable="false"/><el-input-number v-model="stockQuantity" :min="-(current?.stock||0)" :max="9999" style="width:100%"/></div><template #footer><el-button @click="stockDialog=false">取消</el-button><el-button type="primary" class="primary-btn" :disabled="stockQuantity===0" @click="saveStock">确认调整</el-button></template></el-dialog></div></template>
<script setup lang="ts">
import{computed,onMounted,reactive,ref}from'vue';import{ElMessage,ElMessageBox,type FormInstance,type FormRules}from'element-plus';import{Plus,Search,Refresh}from'@element-plus/icons-vue';import{addMedicine,adjustMedicineStock,deleteMedicine,getMedicineCategories,getMedicinePage,updateMedicine}from'@/api/medicine';import type{Medicine,MedicineCategory}from'@/types';const loading=ref(false),saving=ref(false),dialog=ref(false),stockDialog=ref(false),page=ref(1),size=ref(10),total=ref(0),keyword=ref(''),categoryId=ref<number>(),list=ref<Medicine[]>([]),categories=ref<MedicineCategory[]>([]),formRef=ref<FormInstance>(),current=ref<Medicine>(),stockQuantity=ref(0);const form=reactive<Medicine>({name:'',categoryId:undefined,categoryName:'',specification:'',unit:'盒',price:0,stock:0,manufacturer:'',description:''});const rules:FormRules={name:[{required:true,message:'请输入药品名称',trigger:'blur'}],price:[{required:true,message:'请输入价格',trigger:'blur'}],stock:[{required:true,message:'请输入库存',trigger:'blur'}]};const lowStockCount=computed(()=>list.value.filter(x=>x.stock<20).length);const loadData=async()=>{loading.value=true;try{const r=await getMedicinePage({keyword:keyword.value||undefined,categoryId:categoryId.value,page:page.value,size:size.value});list.value=r.data.data.content;total.value=r.data.data.totalElements}finally{loading.value=false}};const search=()=>{page.value=1;loadData()};const reset=()=>Object.assign(form,{id:undefined,name:'',categoryId:undefined,categoryName:'',specification:'',unit:'盒',price:0,stock:0,manufacturer:'',description:''});const openAdd=()=>{reset();dialog.value=true};const openEdit=(row:Medicine)=>{Object.assign(form,row);dialog.value=true};const changeCategory=(id:number)=>{form.categoryName=categories.value.find(c=>c.id===id)?.name||''};const save=async()=>{if(!await formRef.value?.validate().catch(()=>false))return;saving.value=true;try{form.id?await updateMedicine({...form}):await addMedicine({...form});ElMessage.success(form.id?'药品更新成功':'药品新增成功');dialog.value=false;loadData()}finally{saving.value=false}};const openStock=(row:Medicine)=>{current.value=row;stockQuantity.value=0;stockDialog.value=true};const saveStock=async()=>{await adjustMedicineStock(current.value!.id!,stockQuantity.value);ElMessage.success('库存调整成功');stockDialog.value=false;loadData()};const remove=async(row:Medicine)=>{await ElMessageBox.confirm(`确定删除药品“${row.name}”吗？`,'删除药品',{type:'warning'});await deleteMedicine(row.id!);ElMessage.success('药品已删除');loadData()};onMounted(async()=>{categories.value=(await getMedicineCategories()).data.data;loadData()})
</script>
<style scoped>.inventory-note{position:relative;z-index:2;display:flex;align-items:center;gap:11px;min-width:190px;padding:14px 17px;border:1px solid rgba(255,255,255,.17);border-radius:14px;background:rgba(255,255,255,.1)}.inventory-note>.el-icon{font-size:24px;color:#85ead7}.inventory-note span,.inventory-note strong{display:block}.inventory-note span{font-size:9px;opacity:.6}.inventory-note strong{margin-top:3px;font-size:12px}.medicine-cell{display:flex;align-items:center;gap:11px}.medicine-cell>span{width:39px;height:39px;display:flex;align-items:center;justify-content:center;border-radius:12px;background:#e8f6f3;color:#0b9283}.medicine-cell strong,.medicine-cell small{display:block}.medicine-cell small{margin-top:3px;color:#99a8ad;font-size:9px}.price{color:#e18726}.stock strong,.stock span{display:block}.stock strong{font-size:12px}.stock strong.low{color:#d35c5c}.stock span{margin-top:4px;font-size:8px}.stock .ok{color:#26916a}.stock .warn{color:#d35c5c}.form-grid{display:grid;grid-template-columns:1fr 1fr;gap:0 20px}.span-two{grid-column:1/-1}.stock-dialog>div{display:flex;justify-content:space-between;margin-bottom:12px}.stock-dialog>div span{color:#82969d}.stock-dialog .el-alert{margin:16px 0}</style>
